INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00321', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲繳交新臺幣（下同）2 萬元之團費，參加乙旅行社舉辦之日本東京4 日 之半自助旅遊團。乙安排團進團出之來回機票旅程，並提供抵達東京第一 天之交通接駁與四星級膳宿，以及返國前至某特約商店之購物行程。下列 何者錯誤？', '["如因乙之疏失致甲延誤1日抵達東京，甲就其旅程耽延之時間浪費，得 向乙請求不超過5千元之賠償金額", "旅遊開始前，甲非有正當理由，不得變更而改由其朋友參加旅遊", "甲在乙安排之特約商店買到贋品，甲得於1個月內請求乙協助其處理", "乙非有不得已之事由，不得變更交通接駁與膳宿旅館之給付內容"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00322', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列何者，非屬民法物權編所承認之物權種類？', '["以可讓與之債權或其他權利為標的物所設定之質權", "以土地上下之一定空間範圍為標的物所設定之區分地上權", "以地上權、農育權或典權為標的物所設定之抵押權", "以土地上下之一定空間範圍為標的物所設定之區分所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00323', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲向乙購買 A 屋，價金新臺幣 500 萬元，約定 3 個月後移轉 A 屋並辦理 所有權移轉登記。甲交付價金後，請求乙先將A屋交付，供其使用，乙應 允而交付之。隔日，A屋被丙縱火焚燬。下列何者錯誤？', '["若當事人未另有約定，依民法規定，價金給付之危險，由甲負擔", "甲得向丙請求賠償，其損害賠償之利益，由甲取得", "乙得向丙請求侵害所有權之損害賠償責任", "甲得向乙請求，讓與乙對丙針對所有權之侵害，所得主張之損害賠償請 求權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00324', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲將其土地上設定普通抵押權於乙後，如甲自行出資於該土地上興建房 屋，下列何者正確？', '["甲應徵得抵押權人乙之同意，始得於該地上營造建築物", "乙得主張抵押物之價值，因可歸責於抵押人甲之事由致減少者，請求回 復原狀", "乙於實行抵押權拍賣抵押物時，該地上建築物，視為已有地上權之設定", "乙於必要時，得於強制執行程序中聲請法院將該建築物與土地併付拍賣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00325', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', 'A大廈全體區分所有人間訂立住戶規約，A大廈之區分所有人甲另單獨與 其相鄰住戶之區分所有人乙約定，乙每晚 10 時後，須利用耳機收看電視 節目。下列何者錯誤？', '["乙死亡時，其繼承人無論是否知悉甲乙間之約定，均應受該約定拘束", "乙之區分所有權之受讓人無論是否知悉甲乙間之約定，均應受該約定拘束", "甲之區分所有權之受讓人無論是否知悉，均應受A大廈之規約拘束", "甲之區分所有房地之承租人無論是否知悉，均應受A大廈之規約拘束"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00326', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '下列不動產共有人所為之行為，何者應經全體同意，始得為之？', '["將共有物之不動產設定普通抵押權於第三人", "將共有物之不動產出賣，並移轉所有權登記於第三人", "將其應有部分無償贈與，並移轉所有權登記於第三人", "將其應有部分設定普通抵押權於第三人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00327', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於動產物權取得之敘述，下列何者正確？', '["占有無人繼承之動產者，得主張先占無主物而取得所有權", "對於漂流物、沈沒物，得準用關於拾得遺失物之規定而取得所有權", "拾得遺失物起逾6個月，未經有受領權之人認領者，逕由拾得人取得其 所有權", "發見足供藝術、考古或歷史資料之埋藏物者，依民法規定，應由發見人 與國家各取得埋藏物之半"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00328', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '民法第759條規定：因法院之判決，於登記前已取得不動產物權者，應經 登記，始得處分其物權。該條所謂之法院判決，不包括下列何者？', '["因暴利行為而撤銷不動產物權移轉之判決", "因詐害行為而撤銷不動產物權移轉之判決", "請求出賣人履行不動產移轉登記之判決", "共有人訴請裁判分割共有不動產之判決"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00329', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '甲乙為兄弟。乙丙為夫妻。甲收養丁為養子。乙因病辭世，丙與丁結婚。 其婚姻為：', '["效力未定", "得撤銷", "無效", "有效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00330', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-112-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'single_choice', '關於子女稱姓之敘述，下列何者正確？', '["收養以書面為之者，養子女應從收養者之姓", "父母之一方顯有未盡保護教養義務，法院得依父母他方請求為子女利益 宣告變更子女姓氏", "子女之從姓，於該子女出生登記前，因父母約定不成者，得聲請法院 決定", "養子女實際上冠以本姓，已影響收養關係之成立"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:29+00:00", "source_pdf_sha1": "a03a8c333a01", "answer_pdf_sha1": "e7a36083acbf", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "305", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
